import React from "react"
import { Link } from "gatsby"
import "../styles/global.css"

const Layout = ({ children, activeNav }) => (
  <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
    <header className="deals-header">
      <div className="header-left">
        <Link to="/" className="logo-link">
          <span style={{ fontSize: "1.4rem" }}>📦</span>
          <span className="logo-text">DevBundles</span>
        </Link>
      </div>
      <nav className="header-nav">
        <Link to="/" className={`nav-link ${activeNav === "home" ? "nav-link-active" : ""}`}>Bundles</Link>
        <Link to="/deals/" className={`nav-link ${activeNav === "deals" ? "nav-link-active" : ""}`}>All Deals</Link>
        <Link to="/categories/" className={`nav-link ${activeNav === "categories" ? "nav-link-active" : ""}`}>Categories</Link>
      </nav>
    </header>
    <main className="deals-main">{children}</main>
    <footer className="deals-footer">
      <span>Pricing verified daily · Infrastructure costs only · No affiliate links</span>
      <span>DevBundles by solo.engineer</span>
    </footer>

    {/* Mobile Nav */}
    <nav className="mobile-nav">
      <Link to="/" className={`mobile-nav-link ${activeNav === "home" ? "mobile-nav-active" : ""}`}>
        <span className="mobile-nav-icon">📦</span>
        <span className="mobile-nav-label">Bundles</span>
      </Link>
      <Link to="/deals/" className={`mobile-nav-link ${activeNav === "deals" ? "mobile-nav-active" : ""}`}>
        <span className="mobile-nav-icon">💰</span>
        <span className="mobile-nav-label">Deals</span>
      </Link>
      <Link to="/categories/" className={`mobile-nav-link ${activeNav === "categories" ? "mobile-nav-active" : ""}`}>
        <span className="mobile-nav-icon">📂</span>
        <span className="mobile-nav-label">Categories</span>
      </Link>
    </nav>
  </div>
)

export default Layout
